import { ScrambleText } from "@/components/ui/scramble-text";

export default function TerminalHero() {
  return (
    <div className="py-20 text-center bg-black rounded-xl">
      <ScrambleText
        text="System online."
        className="text-4xl font-bold text-green-400"
        scrambleDuration={1800}
      />
    </div>
  );
}

"use client";
import { ScrambleText } from "@/components/ui/scramble-text";

export default function HoverNav() {
  return (
    <div className="flex gap-6 p-10">
      {["Home", "Work", "About", "Contact"].map((label) => (
        <ScrambleText
          key={label}
          text={label}
          triggerOnView={false}
          className="text-lg font-medium text-neutral-300 cursor-pointer hover:text-white"
          scrambleDuration={600}
        />
      ))}
    </div>
  );
}

import { ScrambleText } from "@/components/ui/scramble-text";

export default function QuoteReveal() {
  return (
    <blockquote className="py-16 px-8 max-w-2xl mx-auto border-l-2 border-purple-500">
      <ScrambleText
        text="The best UI is the one users never have to think about."
        className="text-xl italic text-neutral-200"
        scrambleDuration={2000}
        speed={25}
      />
    </blockquote>
  );
}
